import org.junit.runner.RunWith
import org.robolectric.Robolectric

@RunWith(AndroidJUnit4::class)
class SingleFragmentActivityTest : RobolectricTest() {

    @Test
    fun dispatchKeyEvent_whenFragmentHandlesEvent_returnsTrue() {
        val intent = SingleFragmentActivity.getIntent(
            targetContext,
            TestDispatchFragment::class
        )

        val controller = Robolectric.buildActivity(SingleFragmentActivity::class.java, intent).setup()
        val activity = controller.get()

        // Setup fragment to handle the event
        val fragment = activity.supportFragmentManager.findFragmentById(R.id.fragment_container) as TestDispatchFragment
        fragment.shouldHandle = true

        val event = KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_DPAD_CENTER)
        val result = activity.dispatchKeyEvent(event)

        assertTrue("Event should be handled", result)
    }

    @Test
    fun dispatchKeyEvent_whenFragmentDoesNotHandleEvent_callsSuper() {
        val intent = SingleFragmentActivity.getIntent(
            targetContext,
            TestDispatchFragment::class
        )

        val controller = Robolectric.buildActivity(SingleFragmentActivity::class.java, intent).setup()
        val activity = controller.get()

        // Setup fragment to NOT handle the event
        val fragment = activity.supportFragmentManager.findFragmentById(R.id.fragment_container) as TestDispatchFragment
        fragment.shouldHandle = false

        val event = KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_BACK)

        activity.dispatchKeyEvent(event)

        // Check if activity is finishing. 
        // This works because the default implementation of dispatchKeyEvent (KEYCODE_BACK) calls onBackPressed, which finishes the activity.
        // If the bug is present, super.dispatchKeyEvent is NOT called, so onBackPressed is NOT called, and activity is NOT finishing.
        assertTrue("Activity should be finishing", activity.isFinishing)
    }
}

class TestDispatchFragment : Fragment(), DispatchKeyEventListener {
    var shouldHandle = false

    override fun dispatchKeyEvent(event: KeyEvent): Boolean {
        return shouldHandle
    }
}
